/**
 * Utility for creating a DBB {@link MetadataStore} connection from a
 * {@code db2Connection.conf} file and a password file.
 *
 * <p>Centralises the connection pattern shared by {@code GetBuildMapFields.groovy},
 * {@code QueryBuildMap.groovy}, and {@link ZosBuildMapClient#fromConf}.
 *
 * @see ZosBuildMapClient#fromConf
 */
@Slf4j
class MetadatastoreFactory {

    /**
     * Opens a {@link MetadataStore} authenticating with {@code userId} and {@code pwFile}.
     *
     * @param userId     DB2 user ID.
     * @param pwFile     File containing the DB2 password.
     * @param configFile {@code db2Connection.conf} to read; defaults to
     *                   {@code ${DBB_CONF:-${DBB_HOME}/conf}/db2Connection.conf}.
     */
    static MetadataStore connect(String userId, File pwFile,
                                 File configFile = defaultConfigFile()) {
        log.info("Connecting to metadata store: user='{}' configFile='{}'", userId, configFile)
        Properties properties = new Properties()
        configFile.withInputStream { stream -> properties.load(stream) }
        return MetadataStoreFactory.createDb2MetadataStore(userId, pwFile, properties)
    }

    /** Convenience overload accepting the password file as a path string. */
    static MetadataStore connect(String userId, String pwFilePath,
                                 File configFile = defaultConfigFile()) {
        // verify that pwFile exists before proceeding
        File pwFile = new File(pwFilePath)
        if (!pwFile.exists()) {
            log.error("DB2 password file not found at '{}'", pwFile.canonicalPath)
            throw new IllegalStateException("DB2 password file not found at ${pwFile.canonicalPath}")
        }
        return connect(userId, pwFile, configFile)
    }

    private static File defaultConfigFile() {
        String confDir = System.getenv('DBB_CONF') ?: "${System.getenv('DBB_HOME')}/conf"
        // check that the file exists before returning it, to avoid confusion with a missing env var or typo in DBB_HOME
        File confFile = new File(confDir, 'db2Connection.conf')
        if (!confFile.exists()) {
            log.error("DB2 config file not found at '{}' — check DBB_CONF or DBB_HOME", confFile.canonicalPath)
            throw new IllegalStateException("DB2 config file not found at ${confFile.canonicalPath} — check DBB_CONF or DBB_HOME environment variables")
        }
        log.debug("Using DB2 config: {}", confFile)
        return confFile
    }
}

// --- PathVariableExtractor.groovy ---
/**
 * Extracts per-file template variables from a source path.
 *
 * <p>Identifies the application segment in the path (the component whose
 * underscore-delimited tokens satisfy {@code tokens[2] =~ /\d+/}), then
 * looks up the C1STAGE in the stage map using {@code PATH_LO|buildEnv}.
 *
 * <p>Returns a map with keys {@code C1STAGE}, {@code C1SYSTEM}, {@code HLQ}.
 *
 * @see StageMapLoader
 * @see LibraryNameResolver
 */
@Slf4j
class PathVariableExtractor {

    Map<String, String> extract(String sourcePath, String buildEnv,
                                Map<String, String> stageMap, String hlq) {
        def segment = sourcePath.tokenize('/').find { part ->
            def tokens = part.split('_')
            tokens.size() >= 5 && tokens[2] ==~ /\d+/
        }
        if (!segment)
            throw new IllegalArgumentException(
                "No application segment found in source path: '${sourcePath}'"
            )

        def tokens   = segment.split('_')
        def c1system = tokens[1]
        def pathLo   = tokens[2]
        def key      = "${pathLo}|${buildEnv}"
        def c1stage  = stageMap[key]
        if (!c1stage)
            throw new IllegalArgumentException(
                "No stage-map entry for '${key}' (path: '${sourcePath}')"
            )

        def result = [C1STAGE: c1stage, C1SYSTEM: c1system, HLQ: hlq ?: '']
        log.debug("extract: path='{}' env='{}' -> C1STAGE='{}' C1SYSTEM='{}' HLQ='{}'",
                  sourcePath, buildEnv, c1stage, c1system, hlq)
        result
    }
}

// --- PatternMatcher.groovy ---
/**
 * Converts z/OS-style glob patterns to regular expressions and tests whether a value matches.
 *
 * <p>Supported wildcards (aligned with the ISP deletion-rules convention):
 * <ul>
 *   <li>{@code %} — matches exactly one character (equivalent to regex {@code .}).</li>
 *   <li>{@code *} — matches zero or more characters (equivalent to regex {@code .*}).</li>
 * </ul>
 *
 * All other characters are treated as literals.
 *
 * <p>Example: pattern {@code SJCL*} matches {@code SJCL}, {@code SJCLLOAD}, {@code SJCL123},
 * while {@code S%CL} matches only four-character strings starting with S and ending with CL.
 *
 * @see DeletionRule#typePattern
 */
@Slf4j
class PatternMatcher {
    boolean matches(String pattern, String value) {
        def regex = pattern.collect { c ->
            switch (c) {
                case '%': return '.'
                case '*': return '.*'
                default:  return Pattern.quote(String.valueOf(c))
            }
        }.join('')
        def result = value ==~ regex
        log.trace("matches('{}', '{}') = {}", pattern, value, result)
        result
    }
}

// --- PrevEnvCleanLogic.groovy ---
/**
 * DBB post-build task logic: deletes the corresponding cassaforte member from the
 * <em>predecessor</em> environment after a successful compile step.
 *
 * <h3>Purpose</h3>
 * <p>When a source is promoted from environment N-1 to N, the N-1 cassaforte library
 * may still contain a stale copy of the old object.  If the N-1 library participates in
 * a concatenation with N, the stale entry shadows the new one.  This logic removes it
 * so that the concatenation always resolves to the most recently promoted version.
 *
 * <h3>Applicability</h3>
 * <p>Runs only in environments that have a predecessor
 * ({@link EnvironmentChain#requiresPrevEnvClean}): currently {@code ST} and {@code PR}.
 * Returns 0 immediately for all other environments (ATI, ATO, EM).
 *
 * @see DeleteCassaforteLogic
 * @see EnvironmentChain#requiresPrevEnvClean
 * @see EnvironmentChain#getPredecessor
 */
@Slf4j
class PrevEnvCleanLogic {
    DeleteCassaforteLogic deleteLogic
    PathVariableExtractor extractor  = new PathVariableExtractor()
    Map<String, String>   stageMap   = [:]
    String                hlq        = ''
    EnvironmentChain      envChain   = new EnvironmentChain()

    int execute(String sourcePath, String fileType, String environment, String buildGroup) {
        if (!envChain.requiresPrevEnvClean(environment)) {
            log.debug("Skipping prevEnvClean for environment '{}' (no predecessor)", environment)
            return 0
        }
        def prevEnv  = envChain.getPredecessor(environment)
        log.info("Cleaning predecessor '{}' cassaforte for sourcePath='{}'", prevEnv, sourcePath)
        def prevVars = extractor.extract(sourcePath, prevEnv, stageMap, hlq)
        deleteLogic.execute(sourcePath, fileType, prevVars, buildGroup)
    }
}

// --- PuliziaCassaforteImpl.groovy ---
/**
 * Business logic for the {@code PuliziaCassaforte.groovy} entry point.
 *
 * <p>Compiled into {@code pulizia-cassaforte.jar} so it is available on both USS
 * (via {@code groovyz}) and local dev (via {@code groovy}).  Has no IBM/DBB compile-time
 * dependencies — IBM types are accessed via reflection where needed.
 *
 * @see DeleteCassaforteLogic
 * @see SfilamentoLogic
 */
@Slf4j
class PuliziaCassaforteImpl {

    String fileOpsType   = 'zos' // set value to 'local' to use LocalFileOps for file operations, which is useful for testing
    String buildMapClientType = 'db2' // set value to 'json' to read build map from JSON file instead of DB2, which is useful for testing

    // Used by db2 build map client
    String userId        = null
    String pwFilePath    = null
    String db2ConfigPath = null

    // Used by JSON build map client
    String buildMapPath  = null

    // Used by LocalFileOps if fileOpsType is set to 'local'
    String uxBasedir     = null

    // Used by ZosFileOps if fileOpsType is set to 'zos'
    String hlq           = null

    // Default paths to rules and stage map CSVs. Override in tests or when running on USS.
    String rulesPath    = 'build-data/rules.csv'
    File   rulesFile    = null
    String stageMapPath = 'build-data/stage-map.csv'
    File   stageMapFile = null

    BuildMapClient buildMapClient = null
    ZosFileOps fileOps = null

    List rules                    = null
    Map stageMap                  = null
    PathVariableExtractor extractor = null
    EnvironmentChain envChain     = null
    DeleteCassaforteLogic deleteLogic = null
    SfilamentoLogic sfilamento    = null

    int run(String listFileToProcess, String environment, String buildGroup, String configFile = 'PuliziaCassaforte.properties') {
        def props = new Properties()
        new File(configFile).withInputStream { props.load(it) }
        return run(listFileToProcess, environment, buildGroup, props)
    }

    int run(String listFileToProcess, String environment, String buildGroup, Properties props) {
        if (props.getProperty('fileOpsType'))        this.fileOpsType        = props.getProperty('fileOpsType')
        if (props.getProperty('buildMapClientType')) this.buildMapClientType = props.getProperty('buildMapClientType')
        if (props.getProperty('rulesPath'))     this.rulesPath     = props.getProperty('rulesPath')
        if (props.getProperty('stageMapPath'))  this.stageMapPath  = props.getProperty('stageMapPath')
        if (props.getProperty('uxBasedir'))     this.uxBasedir     = props.getProperty('uxBasedir')
        if (props.getProperty('hlq'))           this.hlq           = props.getProperty('hlq')
        if (props.getProperty('userId'))        this.userId        = props.getProperty('userId')
        if (props.getProperty('pwFilePath'))    this.pwFilePath    = props.getProperty('pwFilePath')
        if (props.getProperty('db2ConfigPath')) this.db2ConfigPath = props.getProperty('db2ConfigPath')
        if (props.getProperty('buildMapPath'))  this.buildMapPath  = props.getProperty('buildMapPath')

        if (!listFileToProcess)
            throw new IllegalArgumentException('listFileToProcess argument is required')
        File lftp = new File(listFileToProcess)
        if (!lftp.exists()) {
            throw new IllegalArgumentException("listFileToProcess file not found: '$listFileToProcess'")
        }
        if (!rulesPath || !stageMapPath)
            throw new IllegalArgumentException('rulesPath and stageMapPath must be defined in config')
        rulesFile    = new File(rulesPath)
        stageMapFile = new File(stageMapPath)
        if (!rulesFile.exists())
            throw new IllegalArgumentException("rulesPath file not found: '$rulesPath'")
        if (!stageMapFile.exists())
            throw new IllegalArgumentException("stageMapPath file not found: '$stageMapPath'")

        if (buildMapClientType == 'db2') {
            int credCount = [userId, pwFilePath, db2ConfigPath].count { it != null }
            if (credCount == 0)
                throw new IllegalArgumentException('config must define userId (db2) or buildMapPath (json)')
            if (credCount < 3)
                throw new IllegalArgumentException('userId, pwFilePath and db2ConfigPath must all be defined or none')
            this.buildMapClient = BuildMapClientFactory.fromConf(buildGroup, userId, pwFilePath, new File(db2ConfigPath))
        } else if (buildMapClientType == 'json') {
            this.buildMapClient = BuildMapClientFactory.fromJson(new File(buildMapPath))
        } else {
            throw new IllegalArgumentException('config must define userId or buildMapPath')
        }

        if (fileOpsType == 'zos') {
            this.fileOps = ZosFileOpsFactory.createOnZos()
        } else if (fileOpsType == 'local') {
            if (uxBasedir == null)
                throw new IllegalArgumentException('uxBasedir must be defined when fileOpsType is set to local')
            this.fileOps = new LocalFileOps(uxBasedir)
        } else {
            throw new IllegalArgumentException("Unknown fileOpsType '$fileOpsType'")
        }

        rules       = new DeletionRulesLoader().load(rulesFile)
        stageMap    = new StageMapLoader().load(stageMapFile)
        extractor   = new PathVariableExtractor()
        envChain    = new EnvironmentChain()
        deleteLogic = new DeleteCassaforteLogic(ops: fileOps, rules: rules, buildMap: buildMapClient)
        sfilamento  = new SfilamentoLogic(
            ops:         fileOps,
            deleteLogic: deleteLogic,
            rules:       rules,
            envChain:    envChain,
            extractor:   extractor,
            stageMap:    stageMap,
            hlq:         hlq
        )

        log.info("PuliziaCassaforte: processing list='{}' env='{}' buildGroup='{}'",
                 listFileToProcess, environment, buildGroup)
        int processed = 0, errors = 0
        lftp.eachLine { raw ->
            def line = raw.trim()
            if (!line || line.startsWith('#')) return
            def comma = line.indexOf(',')
            if (comma < 0) {
                log.warn("Skipping malformed line: '{}'", line)
                errors++
                return
            }
            def action     = line.substring(0, comma).trim().toUpperCase()
            def sourcePath = line.substring(comma + 1).trim()
            def fileType   = resolveFileType(sourcePath)

            try {
                switch (action) {
                    case 'C':
                        def vars = extractor.extract(sourcePath, environment, stageMap, hlq)
                        deleteLogic.execute(sourcePath, fileType, vars, buildGroup)
                        processed++
                        break
                    case 'S':
                        sfilamento.execute(sourcePath, fileType, environment, buildGroup)
                        processed++
                        break
                    default:
                        log.warn("Unknown action '{}' in line: '{}'", action, line)
                        errors++
                }
            } catch (Exception e) {
                log.error("ERROR processing '{}': {}", sourcePath, e.message, e)
                errors++
            }
        }

        log.info("PuliziaCassaforte: processed={} errors={}", processed, errors)
        return errors
    }

    private static String resolveFileType(String sourcePath) {
        def filename = sourcePath.tokenize('/').last()
        def ext = filename.contains('.') ? filename.substring(filename.lastIndexOf('.') + 1) : filename
        ext.toUpperCase().padRight(8).take(8)
    }
}

// --- QueryBuildMapImpl.groovy ---
/**
 * Query build map using jar
 */
@Slf4j
class QueryBuildMapImpl {

    /**
     * Queries the build map for each source path in the list file against the live DBB metadata store.
     *
     * @param listFile      Path to the list file (one {@code <any>,<sourcePath>} per line).
     * @param buildGroup    DBB build group name.
     * @param userId        DB2 user ID.
     * @param pwFilePath    Path to the DB2 password file.
     * @param db2ConfigFile {@code db2Connection.conf} to use for the metadata store connection.
     * @return Number of errors encountered (0 = success).
     */
    int run(String listFile, String buildGroup,
            String userId, String pwFilePath, File db2ConfigFile) {
        BuildMapClient buildMap
        try {
            buildMap = BuildMapClientFactory.fromConf(buildGroup, userId, pwFilePath, db2ConfigFile)
        } catch (IllegalStateException e) {
            log.warn("build map unavailable: {} — build map lookups will return empty", e.message)
            System.exit(1)
        }
        return execute(listFile, buildGroup, buildMap)
    }

    /**
     * Queries the build map using a pre-captured JSON build map file (local / fallback).
     *
     * @param listFile   Path to the list file.
     * @param buildGroup DBB build group name.
     * @param bmFile     JSON build map file in {@link LocalBuildMapClient} format.
     * @return Number of errors encountered (0 = success).
     */
    int run(String listFile, String buildGroup, File bmFile) {
        return execute(listFile, buildGroup, BuildMapClientFactory.fromJson(bmFile))
    }

    /** Overload with explicit {@link BuildMapClient} — used by tests for injection. */
    int run(String listFile, String buildGroup, BuildMapClient buildMap) {
        return execute(listFile, buildGroup, buildMap)
    }

    private int execute(String listFile, String buildGroup, BuildMapClient buildMap) {
        int processed = 0, errors = 0
        new File(listFile).eachLine { raw ->
            def line = raw.trim()
            if (!line || line.startsWith('#')) return
            def comma = line.indexOf(',')
            if (comma < 0) {
                log.warn("Skipping malformed line: '{}'", line)
                errors++
                return
            }

            def sourcePath = line.substring(comma + 1).trim()
            log.info("Querying build map on '{}' for '{}'", buildGroup, sourcePath)

            try {
                buildMap.getGeneratedObjects(sourcePath, buildGroup).each { genObj ->
                    log.info("{} -> {}", sourcePath, genObj)
                }
                processed++
            } catch (Exception e) {
                log.error("ERROR processing '{}': {}", sourcePath, e.message, e)
                errors++
            }
        }

        log.info("QueryBuildMapImpl: processed={} errors={}", processed, errors)
        return errors
    }
}

// --- SfilamentoLogic.groovy ---
/**
 * Implements the sfilamento (S-action) scenario: delete the current environment's cassaforte
 * member and, if applicable, restore it from the nearest superior environment.
 *
 * <h3>When does sfilamento apply?</h3>
 * <ul>
 *   <li>Only in environment {@code ST} ({@link EnvironmentChain#supportsSfilamento}).</li>
 *   <li>Only for file types matching {@code SJCL*} (JCL source members).</li>
 * </ul>
 *
 * <h3>Restore logic</h3>
 * <p>After deleting the ST cassaforte member, the logic walks {@link EnvironmentChain#getSuperiors}
 * in order (e.g. {@code PR}) and, for each rule matching the file type, looks for the member in
 * that environment's cassaforte library.  The first copy found is restored into the ST
 * TOCOLB library (derived via {@link LibraryNameResolver#toTocolbLibrary}) and the loop stops.
 *
 * <p>Returns {@code true} if a restore was performed, {@code false} if no copy was found
 * or the file type is not sfilamento-eligible.
 *
 * @see DeleteCassaforteLogic
 * @see EnvironmentChain
 * @see LibraryNameResolver#toTocolbLibrary
 */
@Slf4j
class SfilamentoLogic {
    ZosFileOps            ops
    DeleteCassaforteLogic deleteLogic
    List<DeletionRule>    rules
    PathVariableExtractor extractor  = new PathVariableExtractor()
    Map<String, String>   stageMap   = [:]
    String                hlq        = ''
    PatternMatcher        matcher    = new PatternMatcher()
    LibraryNameResolver   resolver   = new LibraryNameResolver()
    EnvironmentChain      envChain   = new EnvironmentChain()

    boolean execute(String sourcePath, String fileType, String environment, String buildGroup) {
        def currentVars = extractor.extract(sourcePath, environment, stageMap, hlq)
        deleteLogic.execute(sourcePath, fileType, currentVars, buildGroup)

        if (!matcher.matches('SJCL*', fileType)) {
            log.debug("Sfilamento skipped: fileType '{}' does not match SJCL*", fileType)
            return false
        }
        if (!envChain.supportsSfilamento(environment)) {
            log.debug("Sfilamento skipped: environment '{}' does not support it", environment)
            return false
        }

        def member   = DeleteCassaforteLogic.memberName(sourcePath)
        def matching = rules.findAll { matcher.matches(it.typePattern, fileType) }
        log.info("Sfilamento: searching restore for member '{}' fileType '{}' in environment '{}'",
                 member, fileType, environment)

        for (String superEnv : envChain.getSuperiors(environment)) {
            def superVars = extractor.extract(sourcePath, superEnv, stageMap, hlq)
            for (def rule : matching) {
                def srcLib = resolver.resolve(rule.libraryTemplate, superVars)
                def src    = "//${srcLib}(${member})"
                if (ops.exists(src)) {
                    def localLib = resolver.resolve(rule.libraryTemplate, currentVars)
                    def tocolb   = resolver.toTocolbLibrary(localLib)
                    def dst      = "//${tocolb}(${member})"
                    log.info("Sfilamento: restoring {} -> {}", src, dst)
                    ops.copy(src, dst)
                    return true
                }
            }
        }
        log.info("Sfilamento: no restore source found for member '{}' in superiors of '{}'",
                 member, environment)
        return false
    }
}

// --- StageMapLoader.groovy ---
/**
 * Loads the ISP stage-map CSV into a lookup map.
 *
 * <p>CSV format (semicolon-delimited, keys and values wrapped in double-quotes,
 * with optional leading whitespace per line):
 * <pre>
 *   "01|ATO";"X2A"
 * </pre>
 * Key format: {@code PATH_LO|BUILD_ENV} (e.g. {@code "01|ATO"}).
 * Value: C1STAGE code (e.g. {@code "X2A"}).
 */
@Slf4j
class StageMapLoader {

    Map<String, String> load(File file) {
        log.debug("Loading stage map from: {}", file)
        def result = file.readLines()
            .findAll { it.trim() }
            .collectEntries { line ->
                def parts = line.trim().split(';', -1)
                if (parts.size() < 2)
                    throw new IllegalArgumentException("Malformed stage-map row: '$line'")
                def key   = parts[0].trim().replace('"', '')
                def value = parts[1].trim().replace('"', '')
                [key, value]
            }
        log.info("Loaded {} stage-map entries from: {}", result.size(), file)
        result
    }
}

// --- ZosBuildMapClient.groovy ---
// Mainframe-only. Must be compiled and run with groovyz on z/OS USS.
// After upload to USS: chtag -tc IBM-1047 ZosBuildMapClient.groovy

/**
 * USS implementation of {@link BuildMapClient} that queries the live DBB metadata store
 * to resolve generated output objects for a given source file.
 *
 * <p>The {@link BuildGroup} is injected at construction time.  There are two acquisition paths:
 * <ul>
 *   <li><b>DBB task context</b> ({@code PuliziaPostBuild.groovy}): the {@code MetadataInit}
 *       built-in task populates {@code BUILD_GROUP} in the {@link com.ibm.dbb.task.BuildContext};
 *       pass {@code context.get('BUILD_GROUP') as BuildGroup} directly.</li>
 *   <li><b>Standalone USS script</b> ({@code PuliziaCassaforte.groovy}): use
 *       {@link #fromConf(String, String, String)} which reads {@code db2Connection.conf}
 *       and constructs the client in one call.</li>
 * </ul>
 *
 * <p>If no build map has been recorded for the given source path within the group, an empty
 * list is returned rather than throwing.
 *
 * <p>Packaged separately into {@code pulizia-cassaforte-zos.jar} (requires IBM DBB jars in libs/).
 * Must not be loaded by a local JVM — instantiated only inside the groovyz USS entry point.
 *
 * @see BuildMapClient
 * @see LocalBuildMapClient
 * @see ZosFileOpsUSS
 */
@Slf4j
class ZosBuildMapClient implements BuildMapClient {

    private final BuildGroup buildGroup

    /**
     * @param buildGroup  DBB {@link BuildGroup} for the current build group.
     *                    In a task context, obtain via {@code context.get('BUILD_GROUP') as BuildGroup}.
     *                    In a standalone script, obtain via
     *                    {@code MetadataStoreFactory.createDb2MetadataStore(...).getBuildGroup(name)}.
     */
    ZosBuildMapClient(BuildGroup buildGroup) {
        this.buildGroup = buildGroup
        log.debug("ZosBuildMapClient initialized for group '{}'", buildGroup?.getName())
    }

    /**
     * Creates a client by reading DB2 connection properties from {@code db2Connection.conf}
     * in {@code confDir} and connecting to the named build group.
     *
     * <p>Mirrors the connection pattern used by {@code GetBuildMapFields.groovy} and
     * {@code QueryBuildMap.groovy}: reads {@code url}, {@code user}, and {@code password}
     * keys from the conf file, then delegates to
     * {@link MetadataStoreFactory#createDb2MetadataStore(String, String, Properties)}.
     *
     * @param confDir        Directory containing {@code db2Connection.conf}
     *                       (typically {@code $DBB_CONF} or {@code $DBB_HOME/conf}).
     * @param buildGroupName Name of the DBB build group to look up.
     * @param userId         DB2 user ID.
     * @param pwFilePath     Path to the DB2 password file.
     * @throws IllegalStateException if the build group is not found in the metadata store.
     */
    static ZosBuildMapClient fromConf(String confDir, String buildGroupName,
                                      String userId, String pwFilePath) {
        log.info("Connecting to metadata store: user='{}' group='{}' confDir='{}'",
                 userId, buildGroupName, confDir)
        def store = MetadatastoreFactory.connect(userId, pwFilePath,
                                                 new File(confDir, 'db2Connection.conf'))
        BuildGroup group = store.getBuildGroup(buildGroupName)
        if (!group) {
            log.error("Build group '{}' not found in metadata store", buildGroupName)
            throw new IllegalStateException("Build group '${buildGroupName}' not found in metadata store")
        }
        return new ZosBuildMapClient(group)
    }

    /**
     * Returns the output PDS members produced from {@code sourcePath} in the build map
     * stored under that path within the injected {@link BuildGroup}.
     *
     * <p>Uses {@link BuildGroup#getBuildMap(String)} keyed by {@code sourcePath} — the same
     * label convention used by DBB when recording build outputs.  The {@code buildGroup}
     * parameter is ignored (already baked into the injected {@link BuildGroup}).
     *
     * @param sourcePath  Repository-relative source file path (the build map label).
     * @param buildGroup  Ignored; scope is fixed by the injected {@link BuildGroup}.
     * @return            List of {@code {library, member}} maps; empty if no record is found.
     */
    List<Map<String, String>> getGeneratedObjects(String sourcePath, String buildGroup) {
        try {
            BuildMap bm = this.buildGroup.getBuildMap(sourcePath)
            if (!bm) {
                log.debug("getGeneratedObjects: no build map entry for '{}'", sourcePath)
                return []
            }

            def result = bm.getOutputs()
                .findAll { it.getDataset() && it.getMember() }
                .collect { [library: it.getDataset(), member: it.getMember()] }
            log.debug("getGeneratedObjects: '{}' -> {} object(s)", sourcePath, result.size())
            return result

        } catch (BuildException e) {
            log.warn("getGeneratedObjects: BuildException for '{}': {}", sourcePath, e.message)
            return []
        }
    }
}

// --- ZosFileOps.groovy ---
/**
 * Trait (interface) that abstracts z/OS file operations consumed by the cassaforte cleanup logic.
 *
 * <p>Two implementations are provided:
 * <ul>
 *   <li>{@link LocalFileOps}    — maps z/OS-style paths onto the local filesystem for unit testing.</li>
 *   <li>{@code ZosFileOpsUSS}   — delegates to IBM JZOS {@code ZFile} on z/OS USS (packaged separately).</li>
 * </ul>
 *
 * <p>Path convention used by all implementations:
 * <pre>
 *   //DATASET.NAME(MEMBER)  — PDS/PDSE member
 *   //DATASET.NAME          — sequential dataset or PDS root
 *   /path/to/file           — USS HFS/zFS path (passed through unchanged)
 * </pre>
 */
@Slf4j
trait ZosFileOps {

    abstract boolean exists(String path)
    abstract void    delete(String path)
    abstract void    copy(String src, String dst)
    abstract List<String> list(String container)

}

// --- ZosFileOpsFactory.groovy ---
/**
 * Factory for creating {@link ZosFileOps} instances without IBM/DBB compile-time dependencies.
 *
 * <p>On USS (with {@code ZosFileOpsUSS} on the classpath) returns a live USS implementation;
 * falls back to {@link LocalFileOps} for local dev.
 *
 * @see ZosFileOps
 * @see LocalFileOps
 */
@Slf4j
class ZosFileOpsFactory {

    /** Returns {@code ZosFileOpsUSS} on USS, {@link LocalFileOps} otherwise. */
    static ZosFileOps create() {
        try {
            def impl = createOnZos()
            log.info("Using ZosFileOpsUSS")
            return impl
        } catch (ClassNotFoundException ignored) {
            log.info("ZosFileOpsUSS not found on classpath — using LocalFileOps")
            return mockZos()
        }
    }

    /**
     * Loads and returns a {@code ZosFileOpsUSS} instance via reflection.
     *
     * @throws ClassNotFoundException if {@code ZosFileOpsUSS} is not on the classpath.
     */
    static ZosFileOps createOnZos() {
        log.debug("Loading ZosFileOpsUSS via reflection")
        return Class.forName('ZosFileOpsUSS').newInstance() as ZosFileOps
    }

    /** Returns a {@link LocalFileOps} instance for local testing without z/OS dependencies. */
    static ZosFileOps mockZos() {
        log.debug("Creating LocalFileOps for local testing")
        return new LocalFileOps()
    }
}

// --- ZosFileOpsUSS.groovy ---
// Mainframe-only. Must be compiled and run with groovyz on z/OS USS.
// After upload to USS: chtag -tc IBM-1047 ZosFileOpsUSS.groovy
// ZFile javadoc https://www.ibm.com/docs/en/sdk-java-technology/8?topic=jzos-zfile

/**
 * z/OS USS implementation of the {@link ZosFileOps} trait.
 *
 * Provides file-system operations (exists, delete, copy, list) that transparently
 * target either MVS datasets or USS HFS/zFS paths depending on the path prefix:
 *
 *   //DATASET.NAME          — sequential dataset or PDS without member
 *   //DATASET.NAME(MEMBER)  — PDS/PDSE member
 *   /u/path/to/file         — USS HFS/zFS file or directory (any path not starting with //)
 *
 * The // prefix convention mirrors the JCL DSN= notation used by IBM tools.
 * This class delegates MVS operations to the IBM JZOS {@link ZFile} API and
 * USS operations to standard {@link java.io.File}.
 *
 * Packaged separately into pulizia-cassaforte-zos.jar (requires IBM jars in libs/).
 * Never loaded by a local JVM — instantiated only inside the groovyz USS entry point.
 */
@Slf4j
class ZosFileOpsUSS implements ZosFileOps {

    /**
     * Checks whether a dataset or USS path exists.
     *
     * For MVS paths: queries the system catalog via {@link ZFile#dsExists(String)}.
     * For USS paths: delegates to {@link java.io.File#exists()}.
     *
     * @param path  MVS dataset reference (// prefix) or USS absolute path.
     * @return true if the dataset or file is found.
     */
    boolean exists(String path) {
        if (path.startsWith('//')) {
            // dsExists checks the catalog — does not require the dataset to be allocated
            def result = ZFile.dsExists(mvsName(path))
            log.debug("exists({}): {}", path, result)
            return result
        }
        def result = new File(path).exists()
        log.debug("exists({}): {}", path, result)
        result
    }

    /**
     * Deletes a dataset member, a sequential dataset, or a USS file.
     *
     * For MVS paths: builds the ZFile name spec (DSN or DSN(MEMBER)) and calls
     * {@link ZFile#remove(String)}, which maps to the z/OS remove() system call.
     * For USS paths: delegates to {@link java.io.File#delete()}.
     *
     * @param path  MVS dataset reference (// prefix) or USS absolute path.
     * @throws ZFileException if the MVS remove fails (e.g. dataset in use, not found).
     */
    void delete(String path) {
        log.debug("delete({})", path)
        if (path.startsWith('//')) {
            def (dsn, member) = parseDsn(path)
            // Build the ZFile-style spec: DSN(MEMBER) for PDS members, plain DSN otherwise
            def spec = member ? "${dsn}(${member})" : dsn
            ZFile.remove("//'${spec}'")
            return
        }
        new File(path).delete()
    }

    /**
     * Copies a dataset (or member) to another dataset (or member), or copies a USS file.
     *
     * MVS-to-MVS copy: opens source with {@code rb,type=record} and destination with
     * {@code wb,type=record} so that logical z/OS records are preserved exactly.
     * Reads and writes in chunks of 32760 bytes — the maximum LRECL for RECFM=VB records
     * on z/OS (0x7FF8). Both files are closed in finally blocks to avoid dataset locks
     * even if an exception occurs mid-transfer.
     *
     * USS copy: reads all bytes from src and writes them to dst atomically via Groovy's
     * {@link java.io.File#setBytes(byte[])} assignment — suitable for small USS files.
     *
     * Mixed USS→MVS or MVS→USS is not supported; both paths must be of the same type.
     *
     * @param src  Source: MVS dataset reference (// prefix) or USS path.
     * @param dst  Destination: MVS dataset reference (// prefix) or USS path.
     * @throws ZFileException if the MVS open, read, or write fails.
     */
    void copy(String src, String dst) {
        log.debug("copy({} -> {})", src, dst)
        if (src.startsWith('//') && dst.startsWith('//')) {
            def (srcDsn, srcMember) = parseDsn(src)
            def (dstDsn, dstMember) = parseDsn(dst)
            def srcSpec = srcMember ? "${srcDsn}(${srcMember})" : srcDsn
            def dstSpec = dstMember ? "${dstDsn}(${dstMember})" : dstDsn
            // rb/wb with type=record: ZFile reads/writes complete logical records,
            // preserving RECFM and blocking without EBCDIC↔ASCII translation
            def srcFile = new ZFile("//'${srcSpec}'", 'rb,type=record')
            try {
                def dstFile = new ZFile("//'${dstSpec}'", 'wb,type=record')
                try {
                    // 32760 = max VB block payload (0x7FF8); safe upper bound for any LRECL
                    def buf = new byte[32760]
                    int len
                    while ((len = srcFile.read(buf)) >= 0) {
                        dstFile.write(buf, 0, len)
                    }
                } finally {
                    dstFile.close()
                }
            } finally {
                srcFile.close()
            }
            return
        }
        // USS file copy
        new File(dst).bytes = new File(src).bytes
    }

    /**
     * Lists members of a PDS/PDSE or files in a USS directory.
     *
     * For MVS paths: calls {@link ZFile#listMembers(String)} which returns the directory
     * entries of the PDS/PDSE identified by the dataset name (member component ignored).
     * For USS paths: delegates to {@link java.io.File#list()} for directory entries.
     *
     * @param container  MVS PDS/PDSE reference (// prefix) or USS directory path.
     * @return list of member or file names; empty list if the container is empty or null.
     */
    List<String> list(String container) {
        if (container.startsWith('//')) {
            // listMembers returns null if the PDS has no members — coerce to empty list
            def result = ZFile.listMembers(mvsName(container))?.toList() ?: []
            log.debug("list({}): {} member(s)", container, result.size())
            return result
        }
        def result = new File(container).list()?.toList() ?: []
        log.debug("list({}): {} entry(s)", container, result.size())
        result
    }

    // ─── private helpers ──────────────────────────────────────────────────────

    /**
     * Extracts the dataset name from an MVS path, discarding any member component.
     * Used for catalog-level operations (exists) where only the DSN is needed.
     *
     * Examples:
     *   //MY.DATASET          → MY.DATASET
     *   //MY.DATASET(MEMBER)  → MY.DATASET
     *
     * @param path  MVS path with // prefix.
     * @return dataset name without member.
     */
    private String mvsName(String path) {
        def inner = path.substring(2)
        def m = (inner =~ /^(.+?)\((.+?)\)$/)
        m.matches() ? m.group(1) : inner
    }

    /**
     * Parses an MVS path into a [dsn, member] pair.
     * Returns [dsn, null] when no member component is present.
     *
     * Examples:
     *   //MY.DATASET          → ['MY.DATASET', null]
     *   //MY.DATASET(MEMBER)  → ['MY.DATASET', 'MEMBER']
     *
     * @param path  MVS path with // prefix.
     * @return two-element list [datasetName, memberName]; memberName is null if absent.
     */
    private List<String> parseDsn(String path) {
        def inner = path.substring(2)
        def m = (inner =~ /^(.+?)\((.+?)\)$/)
        m.matches() ? [m.group(1), m.group(2)] : [inner, null]
    }
}

